from collections import deque
class Solution:
    def findTheArrayConcVal(self, nums):
        dq = deque(nums)
        total = 0
        while dq:
            if len(dq) > 1:
                a = dq.popleft()
                b = dq.pop()
                total += int(str(a) + str(b))
            else:
                total += dq.popleft()
        return total

